const crypto = require('crypto');
const config = $('Configuration (EDIT ME)').first().json;
const item = $input.first();

const header = (item.json.headers && item.json.headers['x-poststack-signature']) || '';
const rawBody = item.binary && item.binary.data
  ? Buffer.from(item.binary.data.data, 'base64').toString('utf8')
  : JSON.stringify(item.json.body || {});

// Header format (Stripe/Svix style): t=<unix>,v1=<hex>[,v1=<hex2 during secret rotation>]
let t = null;
const sigs = [];
for (const part of header.split(',')) {
  const eq = part.indexOf('=');
  if (eq === -1) continue;
  const key = part.slice(0, eq).trim();
  const value = part.slice(eq + 1).trim();
  if (key === 't') t = value;
  else if (key === 'v1') sigs.push(value);
}

let valid = false;
if (t && sigs.length && config.webhookSecret) {
  const expected = crypto.createHmac('sha256', config.webhookSecret).update(`${t}.${rawBody}`).digest('hex');
  const withinTolerance = Math.abs(Math.floor(Date.now() / 1000) - Number(t)) <= 300;
  valid = withinTolerance && sigs.some((v1) =>
    v1.length === expected.length && crypto.timingSafeEqual(Buffer.from(expected), Buffer.from(v1)));
}

return [{ json: { valid, body: JSON.parse(rawBody) } }];

const config = $('Configuration (EDIT ME)').first().json;
const event = $input.first().json.body;
const baseUrl = String(config.postStackUrl || '').replace(/\/+$/, '');

// post.published's data.id is the DELIVERY id - resolve it to the editorial post via the list below.
return [{ json: {
  url: `${baseUrl}/api/v1/posts?limit=100`,
  deliveryId: event.data.id,
  platform: event.data.platform || '',
  publishedAt: event.created_at,
} }];

const meta = $('Prepare Post Lookup').first().json;
const items = ($input.first().json.data || {}).items || [];
const post = items.find((p) => p.deliveryId === meta.deliveryId);
if (!post) throw new Error(`No post found for delivery ${meta.deliveryId} in the last 100 posts`);

const text = String(post.description || '').trim();
if (!text) throw new Error('Published post has no text to draft from');
const hashtags = String(post.hashtags || '').trim();
const firstLine = text.split('\n')[0].slice(0, 80);

const paragraphs = text.split(/\n{2,}/).map((p) => `<p>${p.replace(/\n/g, '<br>')}</p>`).join('\n');
const body = `${paragraphs}\n${hashtags ? `<p><em>${hashtags}</em></p>` : ''}<hr><p><small>Drafted automatically from a post published on ${meta.platform} at ${meta.publishedAt}.</small></p>`;

return [{ json: {
  name: `Social repost: ${firstLine}`,
  subject: firstLine,
  body,
} }];
